import{_ as a,o as e,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const c=JSON.parse('{"title":"YouAppi","description":"","frontmatter":{"title":"YouAppi","slug":"youappi"},"headers":[],"relativePath":"marketer-hub/youappi.md","filePath":"marketer-hub/youappi.md"}'),i={name:"marketer-hub/youappi.md"};function n(d,t,s,p,l,h){return e(),o("div",null,[...t[0]||(t[0]=[r('<p><em>[Image: 1328]</em>.png &quot;YouAppi + branch.png&quot;)</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><a href="http://www.youappi.com/" target="_blank" rel="noreferrer">YouAppi</a> is a fully managed solution for premium mobile brands, providing one single point to streamline their mobile media buying. YouAppi&#39;s OneRun platform combines the power of machine learning with our proprietary predictive algorithms, and cohort technology, to analyze the mobile content consumption patterns of over 1.5B users, converting data into profitable users. YouAppi was founded in late 2011 with headquarters in San Francisco and offices in New York, Berlin, London, Beijing, Indonesia, Tokyo, Korea, Russia and Israel. For more information, please visit <a href="http://www.youappi.com/" target="_blank" rel="noreferrer">www.YouAppi.com</a>.</p><h3 id="partner-capabilities" tabindex="-1">Partner Capabilities <a class="header-anchor" href="#partner-capabilities" aria-label="Permalink to &quot;Partner Capabilities&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Capability</th><th>Details</th></tr></thead><tbody><tr><td>Company Type</td><td>Contact support at YouAppi for more information.</td></tr><tr><td>Deep Linking</td><td>Supported</td></tr><tr><td>Attribution</td><td>- Click-Through Attribution - View-Through Attribution</td></tr><tr><td>Ad Campaign Types</td><td>- Retargeting Campaigns</td></tr><tr><td>Ad Formats</td><td>Contact support at YouAppi for more information.</td></tr><tr><td>Click Types</td><td>- Client-side click</td></tr><tr><td>Supported Platforms</td><td>- iOS - Android</td></tr><tr><td>Link Wrapping</td><td>Not Supported</td></tr><tr><td>Cost Ingestion Support</td><td>Supported</td></tr><tr><td>Cost Ingestion Types</td><td>via API (Beta)</td></tr><tr><td>Cost Time Zone</td><td>GMT</td></tr><tr><td>Cost Data Scheduling</td><td>[ 4, 9, 12, 18, 24, 36, 48, 72, 96, 120, 240, 360, 480, 720 ] in hours from midnight</td></tr><tr><td>Pricing Models</td><td>- CPI - CPC - CPA</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable YouAppi, you need to have completed the following:</p><ol><li><p>Created a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Have Branch&#39;s Performance <a href="./packaging.html">product</a> enabled for your Branch Account.</p></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p>Running campaigns through YouAppi.</p></li></ol><h2 id="enable-youappi" tabindex="-1">Enable YouAppi <a class="header-anchor" href="#enable-youappi" aria-label="Permalink to &quot;Enable YouAppi&quot;">​</a></h2><h3 id="_1-enable-youappi-in-branch" tabindex="-1">1. Enable YouAppi in Branch <a class="header-anchor" href="#_1-enable-youappi-in-branch" aria-label="Permalink to &quot;1. Enable YouAppi in Branch&quot;">​</a></h3><p>In the Branch Dashboard under <strong>Ads</strong> &gt; <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer"><strong>Partner Management</strong></a>, find/search for YouAppi. If you&#39;re already logged into the Branch Dashboard, you can also click <a href="https://dashboard.branch.io/ads/partner-management/a_youappi?tab=settings" target="_blank" rel="noreferrer">here</a> to go there directly.</p><p>You&#39;ll need to input your <strong>YouAppi Advertiser ID</strong>. Please reach out to your YouAppi Account Manager for details.</p><p>Click the <strong>Save &amp; Enable</strong> button.</p><p>.png &quot;youappi enable.png&quot;)</p><h3 id="_2-configure-postbacks" tabindex="-1">2. Configure Postbacks <a class="header-anchor" href="#_2-configure-postbacks" aria-label="Permalink to &quot;2. Configure Postbacks&quot;">​</a></h3><p>Enabling YouAppi will automatically enable the following postbacks:</p><ul><li>INSTALL</li></ul><p>.png &quot;youappi postbacks.png&quot;)</p><p>You can configure these postbacks or add more under the <a href="https://dashboard.branch.io/ads/partner-management/a_youappi?tab=postback" target="_blank" rel="noreferrer"><strong>Postback Config</strong></a> tab.</p><h4 id="send-all-events" tabindex="-1">Send All Events <a class="header-anchor" href="#send-all-events" aria-label="Permalink to &quot;Send All Events&quot;">​</a></h4><p>Optionally, you can check the checkbox for a given postback for sending all events. When checked, all events will be sent regardless of attribution. Otherwise, the postback will only fire for events attributed to YouAppi.</p><h4 id="adding-postbacks" tabindex="-1">Adding Postbacks <a class="header-anchor" href="#adding-postbacks" aria-label="Permalink to &quot;Adding Postbacks&quot;">​</a></h4><p>Click the <strong>Add New Postback</strong> button at the bottom of the screen. A modal will appear that will allow you to select an event that you are tracking with the Branch SDKs (including Custom Events).</p><p>.gif &quot;Add New Postbacks.gif&quot;)</p><p>For more in-depth postback configurations, view our guides:</p><ul><li><a href="./basic-postback-configuration.html">Basic Postback Configuration</a></li><li><a href="./advanced-postback-configuration.html">Advanced Postback Configuration</a></li><li><strong>Recommended</strong> 👍 <a href="./testing-postbacks.html">Test Postbacks</a></li></ul><h3 id="_3-configure-attribution-windows" tabindex="-1">3. Configure Attribution Windows <a class="header-anchor" href="#_3-configure-attribution-windows" aria-label="Permalink to &quot;3. Configure Attribution Windows&quot;">​</a></h3><p>After configuring your events, navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_youappi?tab=attribution_windows" target="_blank" rel="noreferrer"><strong>Attribution Windows</strong></a> tab to set windows by attribution type.</p><h4 id="recommended-attribution-windows" tabindex="-1">Recommended Attribution Windows <a class="header-anchor" href="#recommended-attribution-windows" aria-label="Permalink to &quot;Recommended Attribution Windows&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Attribution Type</th><th>Window</th></tr></thead><tbody><tr><td>click to session start</td><td>90 days</td></tr><tr><td>click to install</td><td>30 days</td></tr><tr><td>click to conversion event</td><td>90 days</td></tr><tr><td>impression to session start</td><td>1 day</td></tr><tr><td>impression to install</td><td>1 day</td></tr><tr><td>impression to conversion event.</td><td>1 day</td></tr></tbody></table><h3 id="_4-set-up-cost-data" tabindex="-1">4. Set Up Cost Data <a class="header-anchor" href="#_4-set-up-cost-data" aria-label="Permalink to &quot;4. Set Up Cost Data&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Beta for Non-SANs</p><p>Cost Data for Non-Self-Attributing Networks (Non-SANs) is a feature currently in Beta; be aware that there may be unexpected bugs/behaviors until the full release.</p></div><p>To set up cost ingestion for YouAppi, you will need to authenticate using your API Key. Please reach out to your YouAppi account manager if you have trouble finding these values.</p><p>Enter your API Key, and click <strong>Save Authentication</strong></p><p>.png)</p><h3 id="_5-create-branch-ad-link" tabindex="-1">5. Create Branch Ad Link <a class="header-anchor" href="#_5-create-branch-ad-link" aria-label="Permalink to &quot;5. Create Branch Ad Link&quot;">​</a></h3><p>Next, you&#39;ll need to create a Branch Ad Link for your YouAppi campaigns in order for Branch to properly attribute conversions.</p><p>[.png)</p><p>help.branch.io</p><p>Create Ad Links](/docs/ad-links)</p><p>The Branch Ad Link you create will be placed in your YouAppi campaign.</p><h3 id="_6-verify-data-in-branch" tabindex="-1">6. Verify Data in Branch <a class="header-anchor" href="#_6-verify-data-in-branch" aria-label="Permalink to &quot;6. Verify Data in Branch&quot;">​</a></h3><p>After launching your YouAppi campaigns, and conversions begin to happen, you&#39;ll want to verify data is being sent from Branch to YouAppi. You can look at the <a href="https://dashboard.branch.io/liveview/webhooks" target="_blank" rel="noreferrer">Branch Dashboard&#39;s Liveview Webhook Records</a> and apply the following filter:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Operator</th><th>Value</th></tr></thead><tbody><tr><td>ad partner (3p)</td><td>equals</td><td><code>a_youappi</code></td></tr></tbody></table><p>Once applied, data should flow through the Liveview, and you can see the data being sent to YouAppi from Branch.</p><h4 id="verifying-cost-data" tabindex="-1">Verifying Cost Data <a class="header-anchor" href="#verifying-cost-data" aria-label="Permalink to &quot;Verifying Cost Data&quot;">​</a></h4><p>To verify that cost data is flowing into Branch, you need to have the following:</p><ul><li>Completed all implementation steps above</li><li>You need to already be live with campaigns running for the ad network</li><li>Wait 24 hours for data to be pulled in</li></ul>',48)])])}const b=a(i,[["render",n]]);export{c as __pageData,b as default};
